<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    max-width: 920px;
    margin: 0 auto;
    padding: 20px;
    background: #f4f5f7;
    color: #222;
    line-height: 1.4;
  }
  h1 { margin: 0 0 16px; font-size: 24px; }
  h2 { margin: 0 0 12px; font-size: 16px; color: #444; }
  .panel {
    background: #fff;
    border: 1px solid #e1e4e8;
    border-radius: 6px;
    padding: 16px;
    margin-bottom: 16px;
  }
  .form-row, .filters {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    align-items: flex-end;
  }
  .form-row label, .filters label {
    display: flex;
    flex-direction: column;
    font-size: 12px;
    color: #555;
    gap: 4px;
  }
  input, select {
    padding: 6px 8px;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 14px;
    background: #fff;
    font-family: inherit;
  }
  input:focus, select:focus {
    outline: none;
    border-color: #4a90e2;
    box-shadow: 0 0 0 2px rgba(74,144,226,0.15);
  }
  button {
    padding: 8px 14px;
    border: 1px solid #888;
    background: #eee;
    border-radius: 4px;
    cursor: pointer;
    font-size: 14px;
    font-family: inherit;
  }
  button:hover { background: #ddd; }
  #add-expense {
    background: #4a90e2;
    color: #fff;
    border-color: #4a90e2;
  }
  #add-expense:hover { background: #3a7bc8; }
  #form-error {
    color: #c0392b;
    font-size: 13px;
    margin-top: 10px;
    min-height: 18px;
  }
  .summary {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
  }
  .summary-item {
    background: #f0f2f5;
    padding: 6px 12px;
    border-radius: 4px;
    font-size: 14px;
  }
  .summary-item strong { color: #4a90e2; margin-left: 4px; }
  #total { color: #4a90e2; font-weight: bold; }
  #expense-list {
    list-style: none;
    padding: 0;
    margin: 0;
  }
  .expense {
    display: flex;
    align-items: center;
    padding: 10px 4px;
    border-bottom: 1px solid #eee;
    gap: 12px;
  }
  .expense:last-child { border-bottom: none; }
  .exp-amount {
    font-weight: bold;
    min-width: 80px;
    color: #2c3e50;
  }
  .exp-cat {
    background: #e0e6ed;
    padding: 2px 8px;
    border-radius: 3px;
    font-size: 11px;
    text-transform: uppercase;
    color: #555;
    letter-spacing: 0.5px;
  }
  .exp-date { color: #666; font-size: 13px; min-width: 90px; }
  .exp-note { color: #444; flex: 1; font-size: 13px; }
  .exp-del {
    background: #e74c3c;
    color: #fff;
    border: none;
    padding: 4px 10px;
    border-radius: 3px;
    cursor: pointer;
    font-size: 12px;
  }
  .exp-del:hover { background: #c0392b; }
  .empty {
    color: #888;
    font-style: italic;
    padding: 12px 4px;
    list-style: none;
  }
</style>
</head>
<body>
  <h1>Personal Expense Tracker</h1>

  <div class="panel">
    <h2>Add Expense</h2>
    <form id="expense-form" novalidate>
      <div class="form-row">
        <label>Amount
          <input type="number" id="amount" step="0.01" placeholder="0.00">
        </label>
        <label>Category
          <select id="category">
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </label>
        <label>Date
          <input type="date" id="date">
        </label>
        <label>Note
          <input type="text" id="note" placeholder="optional">
        </label>
        <button type="submit" id="add-expense">Add Expense</button>
      </div>
      <div id="form-error"></div>
    </form>
  </div>

  <div class="panel">
    <h2>Filters</h2>
    <div class="filters">
      <label>Category
        <select id="filter-category">
          <option value="all">All</option>
          <option value="groceries">Groceries</option>
          <option value="transport">Transport</option>
          <option value="bills">Bills</option>
          <option value="fun">Fun</option>
        </select>
      </label>
      <label>From
        <input type="date" id="filter-from">
      </label>
      <label>To
        <input type="date" id="filter-to">
      </label>
      <button type="button" id="clear-filters">Clear Filters</button>
    </div>
  </div>

  <div class="panel">
    <h2>Summary</h2>
    <div class="summary">
      <div class="summary-item">Total: <span id="total">0.00</span></div>
      <div class="summary-item cat-total" data-cat="groceries">Groceries:<strong>0.00</strong></div>
      <div class="summary-item cat-total" data-cat="transport">Transport:<strong>0.00</strong></div>
      <div class="summary-item cat-total" data-cat="bills">Bills:<strong>0.00</strong></div>
      <div class="summary-item cat-total" data-cat="fun">Fun:<strong>0.00</strong></div>
    </div>
  </div>

  <div class="panel">
    <h2>Expenses</h2>
    <ul id="expense-list"></ul>
  </div>

<script>
(function() {
  'use strict';

  var STORAGE_KEY = 'expenses_v1';
  var CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];

  // Load expenses from localStorage
  var expenses = [];
  try {
    var raw = localStorage.getItem(STORAGE_KEY);
    if (raw) {
      var parsed = JSON.parse(raw);
      if (Array.isArray(parsed)) {
        expenses = parsed.filter(function(e) {
          return e && typeof e.amount === 'number' && isFinite(e.amount) &&
                 CATEGORIES.indexOf(e.category) !== -1 &&
                 typeof e.date === 'string' && e.date.length > 0;
        });
      }
    }
  } catch (err) {
    expenses = [];
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (err) {
      // ignore quota errors
    }
  }

  // DOM references
  var form = document.getElementById('expense-form');
  var amountInput = document.getElementById('amount');
  var categoryInput = document.getElementById('category');
  var dateInput = document.getElementById('date');
  var noteInput = document.getElementById('note');
  var formError = document.getElementById('form-error');
  var filterCategory = document.getElementById('filter-category');
  var filterFrom = document.getElementById('filter-from');
  var filterTo = document.getElementById('filter-to');
  var clearFiltersBtn = document.getElementById('clear-filters');
  var totalEl = document.getElementById('total');
  var listEl = document.getElementById('expense-list');
  var catTotalEls = {};
  var catTotalNodes = document.querySelectorAll('.cat-total');
  for (var i = 0; i < catTotalNodes.length; i++) {
    catTotalEls[catTotalNodes[i].dataset.cat] = catTotalNodes[i];
  }

  // Default date to today
  var today = new Date();
  var todayStr = today.getFullYear() + '-' +
    String(today.getMonth() + 1).padStart(2, '0') + '-' +
    String(today.getDate()).padStart(2, '0');
  dateInput.value = todayStr;

  function formatMoney(n) {
    return n.toFixed(2);
  }

  function isVisible(expense) {
    var cat = filterCategory.value;
    if (cat !== 'all' && expense.category !== cat) return false;
    var from = filterFrom.value;
    if (from && expense.date < from) return false;
    var to = filterTo.value;
    if (to && expense.date > to) return false;
    return true;
  }

  function render() {
    // Sort newest first: by date desc, then by insertion order desc
    var sorted = expenses.slice().sort(function(a, b) {
      if (a.date !== b.date) return a.date < b.date ? 1 : -1;
      return (b.id || 0) - (a.id || 0);
    });

    // Clear list
    while (listEl.firstChild) listEl.removeChild(listEl.firstChild);

    var total = 0;
    var catTotals = {};
    CATEGORIES.forEach(function(c) { catTotals[c] = 0; });

    var visibleCount = 0;
    sorted.forEach(function(exp) {
      if (!isVisible(exp)) return;
      visibleCount++;
      total += exp.amount;
      catTotals[exp.category] = (catTotals[exp.category] || 0) + exp.amount;

      var li = document.createElement('li');
      li.className = 'expense';
      li.dataset.id = exp.id;

      var amt = document.createElement('span');
      amt.className = 'exp-amount';
      amt.textContent = '$' + formatMoney(exp.amount);

      var cat = document.createElement('span');
      cat.className = 'exp-cat';
      cat.textContent = exp.category;

      var date = document.createElement('span');
      date.className = 'exp-date';
      date.textContent = exp.date;

      var note = document.createElement('span');
      note.className = 'exp-note';
      note.textContent = exp.note || '';

      var del = document.createElement('button');
      del.className = 'exp-del';
      del.type = 'button';
      del.textContent = 'Delete';
      del.addEventListener('click', (function(expense) {
        return function() {
          expenses = expenses.filter(function(e) { return e.id !== expense.id; });
          save();
          render();
        };
      })(exp));

      li.appendChild(amt);
      li.appendChild(cat);
      li.appendChild(date);
      li.appendChild(note);
      li.appendChild(del);
      listEl.appendChild(li);
    });

    if (visibleCount === 0) {
      var empty = document.createElement('li');
      empty.className = 'empty';
      empty.textContent = expenses.length === 0
        ? 'No expenses yet. Add one above to get started.'
        : 'No expenses match the current filters.';
      listEl.appendChild(empty);
    }

    totalEl.textContent = formatMoney(total);
    CATEGORIES.forEach(function(c) {
      var el = catTotalEls[c];
      if (el) {
        var strong = el.querySelector('strong');
        if (strong) {
          strong.textContent = formatMoney(catTotals[c]);
        } else {
          el.textContent = c.charAt(0).toUpperCase() + c.slice(1) + ': ' + formatMoney(catTotals[c]);
        }
      }
    });
  }

  form.addEventListener('submit', function(e) {
    e.preventDefault();
    var rawAmount = amountInput.value;
    var amount = parseFloat(rawAmount);
    var date = dateInput.value;

    // Validation: empty, non-numeric, zero, or negative amount
    if (rawAmount === null || rawAmount === undefined || String(rawAmount).trim() === '' ||
        isNaN(amount) || !isFinite(amount) || amount <= 0) {
      formError.textContent = 'Please enter a valid amount greater than zero.';
      amountInput.focus();
      return;
    }
    // Validation: missing date
    if (!date || date.trim() === '') {
      formError.textContent = 'Please select a date.';
      dateInput.focus();
      return;
    }

    var expense = {
      id: Date.now() + Math.floor(Math.random() * 1000),
      amount: amount,
      category: categoryInput.value,
      date: date,
      note: noteInput.value.trim()
    };

    expenses.push(expense);
    save();
    render();

    formError.textContent = '';
    amountInput.value = '';
    noteInput.value = '';
    amountInput.focus();
  });

  filterCategory.addEventListener('change', render);
  filterFrom.addEventListener('change', render);
  filterTo.addEventListener('change', render);

  clearFiltersBtn.addEventListener('click', function() {
    filterCategory.value = 'all';
    filterFrom.value = '';
    filterTo.value = '';
    render();
  });

  render();
})();
</script>
</body>
</html>
